// Multi-tier reminder system:
// Tier 1: 1 hour after form sent (gentle nudge)
// Tier 2: 12 hours after form sent (half-day reminder)
// Tier 3: 24 hours after form sent (full-day final reminder)
const now = new Date();
const ONE_HOUR = 1 * 60 * 60 * 1000;
const TWELVE_HOURS = 12 * 60 * 60 * 1000;
const TWENTY_FOUR_HOURS = 24 * 60 * 60 * 1000;

const TIERS = [
  { tier: 1, threshold: ONE_HOUR, label: '1-hour' },
  { tier: 2, threshold: TWELVE_HOURS, label: '12-hour' },
  { tier: 3, threshold: TWENTY_FOUR_HOURS, label: '24-hour' }
];

const needsReminder = [];

for (const item of items) {
  const d = item.json;

  // Skip if form completed
  if (d.form_completed === 'true' || d.form_completed === true) continue;

  // Skip if no sent timestamp
  if (!d.form_sent_at) continue;

  const sentAt = new Date(d.form_sent_at);
  const elapsed = now - sentAt;
  const currentReminderCount = parseInt(d.reminder_count || '0', 10);

  // Find the next tier this lead qualifies for
  for (const tier of TIERS) {
    if (elapsed >= tier.threshold && currentReminderCount < tier.tier) {
      needsReminder.push({
        json: {
          ...d,
          hours_since_sent: Math.round(elapsed / (60 * 60 * 1000)),
          reminder_tier: tier.tier,
          reminder_label: tier.label,
          new_reminder_count: tier.tier
        }
      });
      break; // Only send one reminder per check
    }
  }
}

if (needsReminder.length === 0) {
  return [{ json: { no_reminders_needed: true } }];
}

return needsReminder;

// Build tier-specific reminder SMS
const d = items[0].json;
const callerName = d.caller_name || 'there';
const formUrl = d.form_url || '';
const insuranceType = d.insurance_type || 'insurance';
const tier = d.reminder_tier || 1;

const typeLabels = {
  auto: 'auto insurance', vehicle: 'auto insurance',
  commercial_auto: 'commercial auto insurance', business: 'commercial auto insurance',
  homeowners: 'home insurance', home: 'home insurance', property: 'home insurance',
  condo: 'condo insurance', renters: 'renters insurance',
  dwelling_fire: 'dwelling fire insurance'
};
const typeLabel = typeLabels[insuranceType] || 'insurance';

let smsBody;
if (tier === 1) {
  smsBody = `Hi ${callerName}! Just a friendly reminder to fill out your ${typeLabel} intake form so we can get your quote started: ${formUrl} - Questions? Call us at (808) 593-7746. Mahalo!`;
} else if (tier === 2) {
  smsBody = `Hi ${callerName}, we noticed your ${typeLabel} intake form hasn't been submitted yet. Complete it here to get your quote: ${formUrl} - We're here to help! Call (808) 593-7746.`;
} else {
  smsBody = `Hi ${callerName}, this is our final reminder about your ${typeLabel} intake form: ${formUrl} - We'd love to get your quote going! Feel free to call us at (808) 593-7746 if you need any help.`;
}

return [{
  json: {
    ...d,
    to: d.caller_phone,
    reminder_body: smsBody
  }
}];
